 1→import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
 2→import { get, post, put, del } from "@/lib/api"
 3→import type { Exam, PageResult } from "@/types"
 4→
 5→const ADMIN_EXAMS_KEY = "admin-exams"
 6→
 7→/** 管理员获取试卷列表（分页） */
 8→export function useAdminExamList(page: number, size: number) {
 9→  return useQuery<PageResult<Exam>>({
10→    queryKey: [ADMIN_EXAMS_KEY, page, size],
11→    queryFn: () => get<PageResult<Exam>>(`/api/admin/exams?page=${page}&size=${size}`),
12→  })
13→}
14→
15→/** 创建试卷 */
16→export function useCreateExam() {
17→  const queryClient = useQueryClient()
18→  return useMutation({
19→    mutationFn: (data: Partial<Exam>) => post<Exam>("/api/admin/exams", data),
20→    onSuccess: () => {
21→      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
22→    },
23→  })
24→}
25→
26→/** 更新试卷 */
27→export function useUpdateExam() {
28→  const queryClient = useQueryClient()
29→  return useMutation({
30→    mutationFn: ({ id, ...data }: Partial<Exam> & { id: number }) =>
31→      put<void>(`/api/admin/exams/${id}`, data),
32→    onSuccess: () => {
33→      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
34→    },
35→  })
36→}
37→
38→/** 删除试卷 */
39→export function useDeleteExam() {
40→  const queryClient = useQueryClient()
41→  return useMutation({
42→    mutationFn: (id: number) => del<void>(`/api/admin/exams/${id}`),
43→    onSuccess: () => {
44→      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
45→    },
