import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query"
import { get, post, put, del } from "@/lib/api"
import type { Exam, PageResult } from "@/types"

const ADMIN_EXAMS_KEY = "admin-exams"

/** 管理员获取试卷列表（分页） */
export function useAdminExamList(page: number, size: number) {
  return useQuery<PageResult<Exam>>({
    queryKey: [ADMIN_EXAMS_KEY, page, size],
    queryFn: () => get<PageResult<Exam>>(`/api/admin/exams?page=${page}&size=${size}`),
  })
}

/** 创建试卷 */
export function useCreateExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (data: Partial<Exam>) => post<Exam>("/api/admin/exams", data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 更新试卷 */
export function useUpdateExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: ({ id, ...data }: Partial<Exam> & { id: number }) =>
      put<void>(`/api/admin/exams/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 删除试卷 */
export function useDeleteExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => del<void>(`/api/admin/exams/${id}`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 发布试卷 */
export function usePublishExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/publish`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 取消发布试卷 */
export function useUnpublishExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/unpublish`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 关闭试卷 */
export function useCloseExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/close`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

/** 重新发布试卷 */
export function useReopenExam() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: (id: number) => put<void>(`/api/admin/exams/${id}/reopen`),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: [ADMIN_EXAMS_KEY] })
    },
  })
}

import { useState, useRef } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { ArrowLeft, Plus, Pencil, Trash2, Upload, Download } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { Textarea } from "@/components/ui/textarea"
import { QuestionForm } from "@/components/question-form"
import {
  useQuestionList,
  useAddQuestion,
  useBatchImport,
  useUpdateQuestion,
  useDeleteQuestion,
} from "@/hooks/use-admin-questions"
import type { Question } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/questions")({
  component: ManageQuestionsPage,
})

function ManageQuestionsPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/questions" })
  const examId = Number(id)

  const { data: questions, isLoading } = useQuestionList(examId)
  const addMutation = useAddQuestion()
  const batchImportMutation = useBatchImport()
  const updateMutation = useUpdateQuestion()
  const deleteMutation = useDeleteQuestion()

  const [showAddDialog, setShowAddDialog] = useState(false)
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null)
  const [deleteTarget, setDeleteTarget] = useState<Question | null>(null)
  const [showImportDialog, setShowImportDialog] = useState(false)
  const [importPreview, setImportPreview] = useState<Partial<Question>[] | null>(null)
  const [pasteText, setPasteText] = useState("")
  const fileInputRef = useRef<HTMLInputElement>(null)

  const handleAdd = (data: Partial<Question>) => {
    addMutation.mutate(
      { examId, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.addQuestionSuccess"))
          setShowAddDialog(false)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleUpdate = (data: Partial<Question>) => {
    if (!editingQuestion) return
    updateMutation.mutate(
      { examId, id: editingQuestion.id, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          setEditingQuestion(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(
      { examId, id: deleteTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.deleteSuccess"))
          setDeleteTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const REQUIRED_FIELDS = ["content", "optionA", "optionB", "optionC", "optionD", "correctAnswer"] as const

  /** 校验单条题目数据 */
  const validateQuestion = (item: Record<string, unknown>, index: number): string | null => {
    for (const field of REQUIRED_FIELDS) {
      if (!item[field] || typeof item[field] !== "string" || !(item[field] as string).trim()) {
        return t("admin.invalidQuestionData", { index: index + 1 })
      }
    }
    if (!/^[ABCD]$/.test(item.correctAnswer as string)) {
      return t("admin.invalidQuestionData", { index: index + 1 })
    }
    return null
  }

  /** 解析 JSON 文本并校验 */
  const parseAndValidate = (text: string): Partial<Question>[] | null => {
    try {
      const parsed = JSON.parse(text)
      const items = Array.isArray(parsed) ? parsed : parsed.questions
      if (!Array.isArray(items) || items.length === 0) {
        toast.error(t("admin.invalidJsonFormat"))
        return null
      }
      for (let i = 0; i < items.length; i++) {
        const err = validateQuestion(items[i], i)
        if (err) {
          toast.error(err)
          return null
        }
      }
      return items
    } catch {
      toast.error(t("admin.invalidJsonFormat"))
      return null
    }
  }

  /** 处理文件选择 */
  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    const reader = new FileReader()
    reader.onload = (event) => {
      const text = event.target?.result as string
      const items = parseAndValidate(text)
      if (items) {
        setPasteText(text)
        setImportPreview(items)
      }
    }
    reader.onerror = () => toast.error(t("admin.fileReadError"))
    reader.readAsText(file)
    e.target.value = ""
  }

  /** 处理粘贴文本解析 */
  const handleParsePaste = () => {
    if (!pasteText.trim()) return
    const items = parseAndValidate(pasteText)
    if (items) setImportPreview(items)
  }

  /** 确认导入 */
  const handleImportConfirm = () => {
    if (!importPreview) return
    batchImportMutation.mutate(
      { examId, questions: importPreview },
      {
        onSuccess: () => {
          toast.success(t("admin.importSuccess", { count: importPreview.length }))
          setShowImportDialog(false)
          setImportPreview(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  /** 下载 JSON 模板 */
  const handleDownloadTemplate = () => {
    const template = [
      {
        content: "示例题目 / Example question",
        optionA: "选项A / Option A",
        optionB: "选项B / Option B",
        optionC: "选项C / Option C",
        optionD: "选项D / Option D",
        correctAnswer: "A",
        analysis: "解析说明（可选）/ Analysis (optional)",
      },
    ]
    const blob = new Blob([JSON.stringify(template, null, 2)], { type: "application/json" })
    const url = URL.createObjectURL(blob)
    const a = document.createElement("a")
    a.href = url
    a.download = "questions-template.json"
    a.click()
    URL.revokeObjectURL(url)
  }

  /** 关闭导入弹窗 */
  const closeImportDialog = () => {
    setShowImportDialog(false)
    setImportPreview(null)
    setPasteText("")
  }

  /** 截断文本显示 */
  const truncate = (text: string, maxLen = 50) =>
    text.length > maxLen ? `${text.slice(0, maxLen)}...` : text

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
            <ArrowLeft className="h-4 w-4" />
          </Button>
          <h1 className="text-xl font-semibold">{t("admin.manageQuestions")}</h1>
        </div>
        <div className="flex gap-2">
          <Button variant="outline" onClick={() => setShowImportDialog(true)}>
            <Upload className="h-4 w-4" />
            {t("admin.importQuestions")}
          </Button>
          <Button onClick={() => setShowAddDialog(true)}>
            <Plus className="h-4 w-4" />
            {t("admin.addQuestion")}
          </Button>
        </div>
      </div>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !questions?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="w-16">#</TableHead>
              <TableHead>{t("admin.questionContent")}</TableHead>
              <TableHead className="w-24">{t("admin.correctAnswer")}</TableHead>
              <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {questions.map((q) => (
              <TableRow key={q.id}>
                <TableCell>{q.sortOrder}</TableCell>
                <TableCell>{truncate(q.content)}</TableCell>
                <TableCell>{q.correctAnswer}</TableCell>
                <TableCell>
                  <div className="flex justify-end gap-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.edit")}
                      onClick={() => setEditingQuestion(q)}
                    >
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.delete")}
                      onClick={() => setDeleteTarget(q)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {/* 新增题目弹窗 */}
      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.addQuestion")}</DialogTitle>
          </DialogHeader>
          <QuestionForm onSubmit={handleAdd} onCancel={() => setShowAddDialog(false)} />
        </DialogContent>
      </Dialog>

      {/* 编辑题目弹窗 */}
      <Dialog open={!!editingQuestion} onOpenChange={(open) => !open && setEditingQuestion(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.editQuestion")}</DialogTitle>
          </DialogHeader>
          {editingQuestion && (
            <QuestionForm
              defaultValues={editingQuestion}
              onSubmit={handleUpdate}
              onCancel={() => setEditingQuestion(null)}
            />
          )}
        </DialogContent>
      </Dialog>

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>{t("admin.confirmDeleteQuestionDesc")}</DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
      {/* 导入题目弹窗 */}
      <Dialog open={showImportDialog} onOpenChange={(open) => !open && closeImportDialog()}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.importQuestions")}</DialogTitle>
            <DialogDescription>{t("admin.importQuestionsDesc")}</DialogDescription>
          </DialogHeader>
          <div className="space-y-4">
            <Textarea
              rows={8}
              placeholder={t("admin.pasteJsonPlaceholder")}
              value={pasteText}
              onChange={(e) => {
                setPasteText(e.target.value)
                setImportPreview(null)
              }}
            />
            <div className="flex gap-2">
              <Button variant="outline" onClick={handleParsePaste} disabled={!pasteText.trim()}>
                {t("admin.parseJson")}
              </Button>
              <Button variant="outline" onClick={() => fileInputRef.current?.click()}>
                <Upload className="h-4 w-4" />
                {t("admin.selectFile")}
              </Button>
              <Button variant="ghost" onClick={handleDownloadTemplate}>
                <Download className="h-4 w-4" />
                {t("admin.downloadTemplate")}
              </Button>
              <input
                ref={fileInputRef}
                type="file"
                accept=".json"
                className="hidden"
                onChange={handleFileSelect}
              />
            </div>
            {importPreview && (
              <div className="rounded-md border p-3 space-y-2">
                <p className="text-sm font-medium">
                  {t("admin.importPreview", { count: importPreview.length })}
                </p>
                <div className="max-h-48 overflow-y-auto space-y-1">
                  {importPreview.slice(0, 10).map((q, i) => (
                    <div key={i} className="text-sm text-muted-foreground">
                      {i + 1}. {truncate(q.content ?? "", 60)}
                    </div>
                  ))}
                  {importPreview.length > 10 && (
                    <div className="text-sm text-muted-foreground">...</div>
                  )}
                </div>
              </div>
            )}
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={closeImportDialog}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleImportConfirm}
              disabled={!importPreview || batchImportMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState, useRef } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { ArrowLeft, Plus, Pencil, Trash2, Upload, Download, Lock } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
