  const [importPreview, setImportPreview] = useState<Partial<Question>[] | null>(null)
  const [pasteText, setPasteText] = useState("")
  const fileInputRef = useRef<HTMLInputElement>(null)

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Clock, FileQuestion, RotateCcw } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useExamDetail, useStartExam } from "@/hooks/use-exams"

export const Route = createFileRoute("/_layout/exams/$id")({
  component: ExamDetailPage,
})

function ExamDetailPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = Route.useParams()
  const examId = Number(id)
  const { data: exam, isLoading } = useExamDetail(examId)
  const startMutation = useStartExam()
  const [showConfirm, setShowConfirm] = useState(false)

  const handleStart = () => {
    startMutation.mutate(examId, {
      onSuccess: (res) => {
        // 携带考试状态导航到答题页面
        navigate({
          to: `/exams/${examId}/take`,
          state: {
            recordId: res.recordId,
            questions: res.questions,
            startTime: new Date().toISOString(),
            timeLimitMin: exam!.timeLimitMin,
            examTitle: exam!.title,
          },
        })
      },
      onError: (err) => {
        toast.error(err.message)
        setShowConfirm(false)
      },
    })
  }

  if (isLoading) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.loading")}
      </div>
    )
  }

  if (!exam) {
    return (
      <div className="py-10 text-center text-muted-foreground">
        {t("common.noData")}
      </div>
    )
  }

  const timeDisplay =
    exam.timeLimitMin > 0
      ? t("exam.timeLimitValue", { min: exam.timeLimitMin })
      : t("exam.noTimeLimit")

  const attemptsDisplay =
    exam.remainingAttempts === null
      ? t("exam.unlimited")
      : t("exam.attemptsValue", { count: exam.remainingAttempts })

  const canStart = exam.remainingAttempts === null || exam.remainingAttempts > 0

  return (
    <div className="mx-auto max-w-lg space-y-6">
      {/* 考试信息卡 */}
      <div className="rounded-lg border p-6 space-y-4">
        <h1 className="text-2xl font-bold">{exam.title}</h1>

        <div className="space-y-3 text-sm text-muted-foreground">
          <div className="flex items-center gap-2">
            <FileQuestion className="h-4 w-4" />
            <span>
              {t("exam.questionCountLabel")}: {exam.questionCount}
              {t("exam.questionUnit")}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <Clock className="h-4 w-4" />
            <span>
              {t("exam.timeLimitLabel")}: {timeDisplay}
            </span>
          </div>
          <div className="flex items-center gap-2">
            <RotateCcw className="h-4 w-4" />
            <span>
              {t("exam.remainingAttemptsLabel")}: {attemptsDisplay}
            </span>
          </div>
        </div>

        <Button
          className="w-full"
          size="lg"
          disabled={!canStart}
          onClick={() => setShowConfirm(true)}
        >
          {t("exam.startExam")}
        </Button>

        {!canStart && (
          <p className="text-center text-sm text-destructive">
            {t("exam.noAttemptsLeft")}
          </p>
        )}
      </div>

      {/* 确认弹窗 */}
      <Dialog open={showConfirm} onOpenChange={setShowConfirm}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("exam.confirmStartTitle")}</DialogTitle>
            <DialogDescription>
              {t("exam.confirmStartDesc")}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setShowConfirm(false)}>
              {t("common.cancel")}
            </Button>
            <Button
              onClick={handleStart}
              disabled={startMutation.isPending}
            >
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useQuery, useMutation } from "@tanstack/react-query"
import { get, post } from "@/lib/api"
import type { PageResult } from "@/types"

/** 考生端试卷详情响应 */
export interface ExamDetail {
  id: number
  title: string
  status: string
  timeLimitMin: number
  questionCount: number
  maxAttempts: number
  showAnswer: boolean
  showAnalysis: boolean
  accessMode: string
  remainingAttempts: number | null
}

/** 开始考试响应 */
export interface StartExamResponse {
  recordId: number
  questions: Array<{
    id: number
    content: string
    optionA: string
    optionB: string
    optionC: string
    optionD: string
    sortOrder: number
  }>
}

/** 提交考试响应 */
export interface SubmitExamResponse {
  score: number
  status: string
}

/** 提交考试请求体 */
interface SubmitExamPayload {
  examId: number
  recordId: number
  answers: Array<{ questionId: number; answer: string }>
}

const EXAMS_KEY = "exams"

/** 考生端获取可参加的考试列表 */
export function useExamList(page: number, size: number) {
  return useQuery<PageResult<ExamDetail>>({
    queryKey: [EXAMS_KEY, page, size],
    queryFn: () =>
      get<PageResult<ExamDetail>>(`/api/exams?page=${page}&size=${size}`),
  })
}

/** 考生端获取单个考试详情 */
export function useExamDetail(id: number) {
  return useQuery<ExamDetail>({
    queryKey: [EXAMS_KEY, id],
    queryFn: () => get<ExamDetail>(`/api/exams/${id}`),
    enabled: id > 0,
  })
}

/** 开始考试 mutation */
export function useStartExam() {
  return useMutation<StartExamResponse, Error, number>({
    mutationFn: (examId) =>
      post<StartExamResponse>(`/api/exams/${examId}/start`),
  })
}

/** 提交考试 mutation */
export function useSubmitExam() {
  return useMutation<SubmitExamResponse, Error, SubmitExamPayload>({
    mutationFn: ({ examId, recordId, answers }) =>
      post<SubmitExamResponse>(`/api/exams/${examId}/submit`, {
        recordId,
        answers,
      }),
  })
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { ExamCard } from "@/components/exam-card"
import { useExamList } from "@/hooks/use-exams"

export const Route = createFileRoute("/_layout/exams/")({
  component: ExamListPage,
})

function ExamListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 12
  const { data, isLoading } = useExamList(page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  return (
    <div className="space-y-6">
      <h1 className="text-xl font-semibold">{t("nav.myExams")}</h1>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.loading")}
        </div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("exam.noExams")}
        </div>
      ) : (
        <>
          {/* 试卷卡片网格 */}
          <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
            {data.records.map((exam) => (
              <ExamCard
                key={exam.id}
                exam={exam}
                onClick={() => navigate({ to: `/exams/${exam.id}` })}
              />
            ))}
          </div>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("exam.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("exam.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

