278→    public RecordDetailResponse getRecordDetail(Long recordId, Long userId) {
279→        ExamRecord record = examRecordMapper.selectById(recordId);
280→        if (record == null) {
281→            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
282→        }
283→        if (!record.getUserId().equals(userId)) {
