289→
290→        // 查询答题明细
291→        List<AnswerDetail> answerDetails = answerDetailMapper.selectList(
292→                new LambdaQueryWrapper<AnswerDetail>()
293→                        .eq(AnswerDetail::getRecordId, recordId));
294→
295→        // 查询对应题目
296→        List<Long> questionIds = answerDetails.stream()
297→                .map(AnswerDetail::getQuestionId)
298→                .collect(Collectors.toList());
299→        Map<Long, QuestionBank> questionMap = questionIds.isEmpty()
300→                ? Collections.emptyMap()
301→                : questionBankMapper.selectBatchIds(questionIds).stream()
302→                        .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));
303→
304→        // 构建答题明细 VO
