import { useTranslation } from "react-i18next"
import { Clock, FileQuestion, RotateCcw } from "lucide-react"
import { Badge } from "@/components/ui/badge"
import { cn } from "@/lib/utils"
import type { ExamDetail } from "@/hooks/use-exams"

interface ExamCardProps {
  exam: ExamDetail
  onClick: () => void
}

export function ExamCard({ exam, onClick }: ExamCardProps) {
  const { t } = useTranslation()

  const timeDisplay =
    exam.timeLimitMin > 0
      ? t("exam.timeLimitValue", { min: exam.timeLimitMin })
      : t("exam.noTimeLimit")

  const attemptsDisplay =
    exam.remainingAttempts === null
      ? t("exam.unlimited")
      : t("exam.attemptsValue", { count: exam.remainingAttempts })

  return (
    <div
      className={cn(
        "cursor-pointer rounded-lg border p-5 transition-colors hover:border-primary/50 hover:shadow-md",
      )}
      onClick={onClick}
    >
      {/* 标题行 */}
      <div className="mb-3 flex items-start justify-between gap-2">
        <h3 className="truncate text-base font-bold">{exam.title}</h3>
        <Badge variant="default" className="shrink-0 bg-green-600">
          {t("exam.statusPublished")}
        </Badge>
      </div>

      {/* 信息行 */}
      <div className="space-y-2 text-sm text-muted-foreground">
        <div className="flex items-center gap-1.5">
          <FileQuestion className="h-4 w-4" />
          <span>
            {t("exam.questionCountLabel")}: {exam.questionCount}
            {t("exam.questionUnit")}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <Clock className="h-4 w-4" />
          <span>
            {t("exam.timeLimitLabel")}: {timeDisplay}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <RotateCcw className="h-4 w-4" />
          <span>
            {t("exam.remainingAttemptsLabel")}: {attemptsDisplay}
          </span>
        </div>
      </div>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useNavigate } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useRecordList } from "@/hooks/use-records"
import type { RecordDetail } from "@/hooks/use-records"

export const Route = createFileRoute("/_layout/records/")({
  component: RecordListPage,
})

/** 记录状态 badge 变体映射 */
const STATUS_VARIANT: Record<string, "default" | "destructive"> = {
  submitted: "default",
  timeout: "destructive",
}

function formatStatus(status: string, t: (key: string) => string): string {
  const map: Record<string, string> = {
    submitted: t("exam.statusSubmitted"),
    timeout: t("exam.statusTimeout"),
    in_progress: t("exam.statusInProgress"),
  }
  return map[status] ?? status
}

function formatTimeRange(start: string | null, end: string | null, t: (key: string, opts?: Record<string, unknown>) => string): string {
  if (!start) return "-"
  const s = new Date(start)
  const startStr = s.toLocaleString()
  if (!end) return startStr
  const e = new Date(end)
  const diffSec = Math.round((e.getTime() - s.getTime()) / 1000)
  if (diffSec <= 0) return startStr
  const min = Math.floor(diffSec / 60)
  const sec = diffSec % 60
  return `${startStr}  (${t("exam.durationValue", { min, sec })})`
}

function RecordListPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useRecordList(page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  const handleRowClick = (record: RecordDetail) => {
    navigate({ to: `/records/${record.id}` })
  }

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">{t("nav.records")}</h1>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.loading")}
        </div>
      ) : !data?.records.length ? (
        <div className="py-10 text-center text-muted-foreground">
          {t("common.noData")}
        </div>
      ) : (
        <>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>{t("exam.examTitle")}</TableHead>
                <TableHead>{t("exam.score")}</TableHead>
                <TableHead>{t("exam.status")}</TableHead>
                <TableHead>{t("exam.examTime")}</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {data.records.map((record) => (
                <TableRow
                  key={record.id}
                  className="cursor-pointer hover:bg-muted/50"
                  onClick={() => handleRowClick(record)}
                >
                  <TableCell className="font-medium">
                    {record.examTitle || t("exam.deletedExam")}
                  </TableCell>
                  <TableCell>
                    {record.score !== null
                      ? `${record.score}${t("exam.scoreUnit")}`
                      : "-"}
                  </TableCell>
                  <TableCell>
                    <Badge
                      variant={STATUS_VARIANT[record.status] ?? "default"}
                    >
                      {formatStatus(record.status, t)}
                    </Badge>
                  </TableCell>
                  <TableCell>{formatTimeRange(record.startTime, record.endTime, t)}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>

          {/* 分页 */}
          {totalPages > 1 && (
            <div className="flex items-center justify-end gap-2">
              <Button
                variant="outline"
                size="sm"
                disabled={page <= 1}
                onClick={() => setPage((p) => p - 1)}
              >
                {t("exam.prevPage")}
              </Button>
              <span className="text-sm text-muted-foreground">
                {page} / {totalPages}
              </span>
              <Button
                variant="outline"
                size="sm"
                disabled={page >= totalPages}
                onClick={() => setPage((p) => p + 1)}
              >
                {t("exam.nextPage")}
              </Button>
            </div>
          )}
        </>
      )}
    </div>
  )
}

import { Outlet, createRootRoute } from "@tanstack/react-router"
import { Toaster } from "sonner"

export const Route = createRootRoute({
  component: RootComponent,
})

function RootComponent() {
  return (
    <>
      <Outlet />
      <Toaster richColors position="top-right" />
    </>
  )
}

