package com.exam.config;

import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;

import java.util.Map;

/**
 * Spring Security 配置
 */
@Configuration
@EnableWebSecurity
@RequiredArgsConstructor
public class SecurityConfig {

    private final JwtAuthenticationFilter jwtAuthenticationFilter;
    private final ObjectMapper objectMapper;

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(AbstractHttpConfigurer::disable)
            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/auth/oauth2/**").permitAll()
                .requestMatchers("/api/admin/**").hasRole("ADMIN")
                .requestMatchers("/api/**").authenticated()
                .anyRequest().permitAll()
            )
            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
            .exceptionHandling(ex -> ex
                .authenticationEntryPoint((request, response, authException) -> {
                    response.setStatus(HttpStatus.UNAUTHORIZED.value());
                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
                    response.setCharacterEncoding("UTF-8");
                    String body = objectMapper.writeValueAsString(
                            Map.of("code", 401, "message", "未登录或登录已过期", "data", ""));
                    response.getWriter().write(body);
                })
                .accessDeniedHandler((request, response, accessDeniedException) -> {
                    response.setStatus(HttpStatus.FORBIDDEN.value());
                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
                    response.setCharacterEncoding("UTF-8");
                    String body = objectMapper.writeValueAsString(
                            Map.of("code", 403, "message", "无权限访问", "data", ""));
                    response.getWriter().write(body);
                })
            );

        return http.build();
    }
}

import { useState } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { ArrowLeft } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useScoreAnalysis, useQuestionAnalysis } from "@/hooks/use-admin-analysis"

export const Route = createFileRoute("/_layout/admin/exams/$id/analysis")({
  component: AnalysisPage,
})

function AnalysisPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/analysis" })
  const examId = Number(id)

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-xl font-semibold">{t("admin.analysisTab")}</h1>
      </div>
      <Tabs defaultValue="scores">
        <TabsList>
          <TabsTrigger value="scores">{t("admin.scoreAnalysis")}</TabsTrigger>
          <TabsTrigger value="questions">{t("admin.questionAnalysis")}</TabsTrigger>
        </TabsList>
        <TabsContent value="scores">
          <ScoreTab examId={examId} />
        </TabsContent>
        <TabsContent value="questions">
          <QuestionTab examId={examId} />
        </TabsContent>
      </Tabs>
    </div>
  )
}

/** 得分情况 Tab */
function ScoreTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useScoreAnalysis(examId, page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.records.length) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-4">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>{t("admin.displayName")}</TableHead>
            <TableHead>{t("admin.score")}</TableHead>
            <TableHead>{t("admin.startTime")}</TableHead>
            <TableHead>{t("admin.endTime")}</TableHead>
            <TableHead>{t("admin.attemptNo")}</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.records.map((r, idx) => (
            <TableRow key={`${r.userId}-${r.attemptNo}-${idx}`}>
              <TableCell>{r.displayName}</TableCell>
              <TableCell>{r.score}</TableCell>
              <TableCell>{new Date(r.startTime).toLocaleString()}</TableCell>
              <TableCell>{r.endTime ? new Date(r.endTime).toLocaleString() : "-"}</TableCell>
              <TableCell>{r.attemptNo}</TableCell>
