const STATUS_VARIANT: Record<string, "default" | "destructive"> = {
  submitted: "default",
  timeout: "destructive",
}

function formatStatus(status: string, t: (key: string) => string): string {
  const map: Record<string, string> = {
    submitted: t("exam.statusSubmitted"),
    timeout: t("exam.statusTimeout"),
    in_progress: t("exam.statusInProgress"),
  }
  return map[status] ?? status
}

function formatDateTime(date: Date): string {
  const y = date.getFullYear()
  const M = String(date.getMonth() + 1).padStart(2, "0")
  const d = String(date.getDate()).padStart(2, "0")
  const h = String(date.getHours()).padStart(2, "0")
  const m = String(date.getMinutes()).padStart(2, "0")
  const s = String(date.getSeconds()).padStart(2, "0")
  return `${y}-${M}-${d} ${h}:${m}:${s}`
}

function formatTimeRange(start: string | null, end: string | null, t: (key: string, opts?: Record<string, unknown>) => string): string {
  if (!start) return "-"
  const s = new Date(start)
  const startStr = formatDateTime(s)
  if (!end) return startStr
  const e = new Date(end)
  const diffSec = Math.round((e.getTime() - s.getTime()) / 1000)
  if (diffSec <= 0) return startStr
  const min = Math.floor(diffSec / 60)
  const sec = diffSec % 60
  return `${startStr}  (${t("exam.durationValue", { min, sec })})`
}

