  const handleAdd = (data: Partial<Question>) => {
    addMutation.mutate(
      { examId, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.addQuestionSuccess"))
          setShowAddDialog(false)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleUpdate = (data: Partial<Question>) => {
    if (!editingQuestion) return
    updateMutation.mutate(
      { examId, id: editingQuestion.id, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          setEditingQuestion(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(
      { examId, id: deleteTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.deleteSuccess"))
          setDeleteTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const REQUIRED_FIELDS = ["content", "optionA", "optionB", "optionC", "optionD", "correctAnswer"] as const

  /** 校验单条题目数据 */
  const validateQuestion = (item: Record<string, unknown>, index: number): string | null => {
    for (const field of REQUIRED_FIELDS) {
      if (!item[field] || typeof item[field] !== "string" || !(item[field] as string).trim()) {
        return t("admin.invalidQuestionData", { index: index + 1 })
      }
    }
    if (!/^[ABCD]$/.test(item.correctAnswer as string)) {
      return t("admin.invalidQuestionData", { index: index + 1 })
    }
    return null
  }

  /** 解析 JSON 文本并校验 */
  const parseAndValidate = (text: string): Partial<Question>[] | null => {
    try {
      const parsed = JSON.parse(text)
      const items = Array.isArray(parsed) ? parsed : parsed.questions
      if (!Array.isArray(items) || items.length === 0) {
        toast.error(t("admin.invalidJsonFormat"))
        return null
      }
      for (let i = 0; i < items.length; i++) {
        const err = validateQuestion(items[i], i)
        if (err) {
          toast.error(err)
          return null
        }
      }
      return items
    } catch {
      toast.error(t("admin.invalidJsonFormat"))
      return null
