import { useQuery } from "@tanstack/react-query"
import { get } from "@/lib/api"
import type { PageResult } from "@/types"

/** 得分分析记录 */
export interface ScoreRecord {
  userId: number
  displayName: string
  score: number
  startTime: string
  endTime: string | null
  attemptNo: number
}

/** 题目分析数据 */
export interface QuestionAnalysis {
  questionId: number
  content: string
  totalAnswered: number
  correctCount: number
  correctRate: number
}

/** 获取得分分析（分页） */
export function useScoreAnalysis(examId: number, page: number, size: number) {
  return useQuery<PageResult<ScoreRecord>>({
    queryKey: ["admin-analysis-scores", examId, page, size],
    queryFn: () =>
      get<PageResult<ScoreRecord>>(
        `/api/admin/exams/${examId}/analysis/scores?page=${page}&size=${size}`,
      ),
    enabled: examId > 0,
  })
}

/** 获取题目分析 */
export function useQuestionAnalysis(examId: number) {
  return useQuery<QuestionAnalysis[]>({
    queryKey: ["admin-analysis-questions", examId],
    queryFn: () =>
      get<QuestionAnalysis[]>(`/api/admin/exams/${examId}/analysis/questions`),
    enabled: examId > 0,
  })
}

