package com.exam.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.core.metadata.IPage;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.exam.dto.*;
import com.exam.entity.*;
import com.exam.enums.AccessMode;
import com.exam.enums.ExamStatus;
import com.exam.enums.RecordStatus;
import com.exam.exception.BizException;
import com.exam.exception.ErrorCode;
import com.exam.mapper.*;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.Duration;
import java.time.LocalDateTime;
import java.util.*;
import java.util.function.Function;
import java.util.stream.Collectors;

/**
 * 考生端-考试记录服务
 */
@Slf4j
@Service
public class ExamRecordService {

    private final ExamMapper examMapper;
    private final ExamRecordMapper examRecordMapper;
    private final ExamRecordQuestionMapper examRecordQuestionMapper;
    private final AnswerDetailMapper answerDetailMapper;
    private final QuestionBankMapper questionBankMapper;
    private final ExamWhitelistMapper examWhitelistMapper;

    public ExamRecordService(ExamMapper examMapper,
                             ExamRecordMapper examRecordMapper,
                             ExamRecordQuestionMapper examRecordQuestionMapper,
                             AnswerDetailMapper answerDetailMapper,
                             QuestionBankMapper questionBankMapper,
                             ExamWhitelistMapper examWhitelistMapper) {
        this.examMapper = examMapper;
        this.examRecordMapper = examRecordMapper;
        this.examRecordQuestionMapper = examRecordQuestionMapper;
        this.answerDetailMapper = answerDetailMapper;
        this.questionBankMapper = questionBankMapper;
        this.examWhitelistMapper = examWhitelistMapper;
    }

    /**
     * 考生端-分页查询可参加的考试列表
     */
    public IPage<ExamDetailResponse> listExams(Long userId, int page, int size) {
        // 查询所有已发布考试（数量通常不大）
        List<Exam> publishedExams = examMapper.selectList(
                new LambdaQueryWrapper<Exam>().eq(Exam::getStatus, ExamStatus.PUBLISHED));

        // 按访问权限过滤
        List<ExamDetailResponse> filtered = publishedExams.stream()
                .filter(exam -> hasAccess(exam, userId))
                .map(exam -> buildExamDetailResponse(exam, userId))
                .collect(Collectors.toList());

        // 手动分页
        int total = filtered.size();
        int fromIndex = Math.min((page - 1) * size, total);
        int toIndex = Math.min(fromIndex + size, total);
        List<ExamDetailResponse> pageRecords = filtered.subList(fromIndex, toIndex);

        Page<ExamDetailResponse> result = new Page<>(page, size, total);
        result.setRecords(pageRecords);
        return result;
    }

    /**
     * 考生端-查询考试详情
     */
    public ExamDetailResponse getExamDetail(Long examId, Long userId) {
        Exam exam = getPublishedExamOrThrow(examId);
        checkAccess(exam, userId);
        return buildExamDetailResponse(exam, userId);
    }

    /**
     * 开始考试：校验 → 抽题 → 创建记录
     */
    @Transactional(rollbackFor = Exception.class)
    public ExamStartResponse startExam(Long examId, Long userId) {
        // 1. 校验考试状态
        Exam exam = getPublishedExamOrThrow(examId);

        // 2. 校验访问权限
        checkAccess(exam, userId);

        // 3. 校验最大考试次数
        long completedCount = countCompletedRecords(examId, userId);
        if (exam.getMaxAttempts() > 0 && completedCount >= exam.getMaxAttempts()) {
            throw new BizException(ErrorCode.MAX_ATTEMPTS_REACHED);
        }

        // 4. 校验是否存在进行中的考试
        long inProgressCount = examRecordMapper.selectCount(
                new LambdaQueryWrapper<ExamRecord>()
                        .eq(ExamRecord::getExamId, examId)
                        .eq(ExamRecord::getUserId, userId)
                        .eq(ExamRecord::getStatus, RecordStatus.IN_PROGRESS));
        if (inProgressCount > 0) {
            throw new BizException(ErrorCode.EXAM_IN_PROGRESS);
        }

        // 5. 抽题
        List<QuestionBank> allQuestions = questionBankMapper.selectList(
                new LambdaQueryWrapper<QuestionBank>()
                        .eq(QuestionBank::getExamId, examId)
                        .orderByAsc(QuestionBank::getSortOrder));

        List<QuestionBank> drawnQuestions = drawQuestions(allQuestions, exam.getQuestionCount());

        // 6. 创建考试记录
        ExamRecord record = ExamRecord.builder()
                .examId(examId)
                .userId(userId)
                .startTime(LocalDateTime.now())
                .status(RecordStatus.IN_PROGRESS)
                .attemptNo((int) completedCount + 1)
                .build();
        examRecordMapper.insert(record);

        // 7. 插入记录-题目关联
        for (int i = 0; i < drawnQuestions.size(); i++) {
            ExamRecordQuestion erq = ExamRecordQuestion.builder()
                    .recordId(record.getId())
                    .questionId(drawnQuestions.get(i).getId())
                    .sortOrder(i + 1)
                    .build();
            examRecordQuestionMapper.insert(erq);
        }

        // 8. 构建响应（不含正确答案和解析）
        ExamStartResponse response = new ExamStartResponse();
        response.setRecordId(record.getId());
        List<ExamStartResponse.QuestionVO> questionVOs = new ArrayList<>(drawnQuestions.size());
        for (int i = 0; i < drawnQuestions.size(); i++) {
            QuestionBank q = drawnQuestions.get(i);
            ExamStartResponse.QuestionVO vo = new ExamStartResponse.QuestionVO();
            vo.setId(q.getId());
            vo.setContent(q.getContent());
            vo.setOptionA(q.getOptionA());
            vo.setOptionB(q.getOptionB());
            vo.setOptionC(q.getOptionC());
            vo.setOptionD(q.getOptionD());
            vo.setSortOrder(i + 1);
            questionVOs.add(vo);
        }
        response.setQuestions(questionVOs);

        log.info("[lbl][Exam][START] 开始考试, userId={}, examId={}, recordId={}, questionCount={}",
                userId, examId, record.getId(), drawnQuestions.size());

        return response;
    }

    /**
     * 恢复进行中的考试：校验记录状态 → 返回题目列表
     */
    public ExamStartResponse resumeExam(Long examId, Long recordId, Long userId) {
        ExamRecord record = examRecordMapper.selectById(recordId);
        if (record == null) {
            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
        }
        if (!record.getUserId().equals(userId) || !record.getExamId().equals(examId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }
        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
        }

        // 查询本次考试抽中的题目
        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
                new LambdaQueryWrapper<ExamRecordQuestion>()
                        .eq(ExamRecordQuestion::getRecordId, recordId)
                        .orderByAsc(ExamRecordQuestion::getSortOrder));
        List<Long> questionIds = recordQuestions.stream()
                .map(ExamRecordQuestion::getQuestionId)
                .collect(Collectors.toList());
        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(questionIds)
                .stream()
                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));

        // 构建响应（不含正确答案和解析）
        ExamStartResponse response = new ExamStartResponse();
        response.setRecordId(recordId);
        List<ExamStartResponse.QuestionVO> questionVOs = new ArrayList<>(recordQuestions.size());
        for (ExamRecordQuestion rq : recordQuestions) {
            QuestionBank q = questionMap.get(rq.getQuestionId());
            if (q == null) continue;
            ExamStartResponse.QuestionVO vo = new ExamStartResponse.QuestionVO();
            vo.setId(q.getId());
            vo.setContent(q.getContent());
            vo.setOptionA(q.getOptionA());
            vo.setOptionB(q.getOptionB());
            vo.setOptionC(q.getOptionC());
            vo.setOptionD(q.getOptionD());
            vo.setSortOrder(rq.getSortOrder());
            questionVOs.add(vo);
        }
        response.setQuestions(questionVOs);

        log.info("[lbl][Exam][RESUME] 恢复考试, userId={}, examId={}, recordId={}, questionCount={}",
                userId, examId, recordId, questionVOs.size());

        return response;
    }

    /**
     * 提交考试：评分 → 保存答题明细 → 更新记录
     */
    @Transactional(rollbackFor = Exception.class)
    public ExamSubmitResponse submitExam(ExamSubmitRequest req, Long userId) {
        // 1. 校验记录
        ExamRecord record = examRecordMapper.selectById(req.getRecordId());
        if (record == null) {
            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
        }
        if (!record.getUserId().equals(userId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }
        if (record.getStatus() != RecordStatus.IN_PROGRESS) {
            throw new BizException(ErrorCode.RECORD_ALREADY_SUBMITTED);
        }

        // 2. 判断是否超时
        Exam exam = examMapper.selectById(record.getExamId());
        RecordStatus status;
        if (exam.getTimeLimitMin() != null && exam.getTimeLimitMin() > 0
                && Duration.between(record.getStartTime(), LocalDateTime.now()).toMinutes() > exam.getTimeLimitMin()) {
            status = RecordStatus.TIMEOUT;
        } else {
            status = RecordStatus.SUBMITTED;
        }

        // 3. 获取本次考试抽中的题目
        List<ExamRecordQuestion> recordQuestions = examRecordQuestionMapper.selectList(
                new LambdaQueryWrapper<ExamRecordQuestion>()
                        .eq(ExamRecordQuestion::getRecordId, req.getRecordId()));
        List<Long> drawnQuestionIds = recordQuestions.stream()
                .map(ExamRecordQuestion::getQuestionId)
                .collect(Collectors.toList());

        // 4. 查询题目详情
        Map<Long, QuestionBank> questionMap = questionBankMapper.selectBatchIds(drawnQuestionIds)
                .stream()
                .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));

        // 5. 评分
        int totalQuestions = drawnQuestionIds.size();
        BigDecimal pointsPerQuestion = new BigDecimal(100)
                .divide(new BigDecimal(totalQuestions), 2, RoundingMode.HALF_UP);
        int correctCount = 0;

        for (AnswerItem item : req.getAnswers()) {
            QuestionBank question = questionMap.get(item.getQuestionId());
            boolean isCorrect = question != null && item.getAnswer().equals(question.getCorrectAnswer());
            if (isCorrect) {
                correctCount++;
            }

            // 保存答题明细
            AnswerDetail detail = AnswerDetail.builder()
                    .recordId(req.getRecordId())
                    .questionId(item.getQuestionId())
                    .userAnswer(item.getAnswer())
                    .isCorrect(isCorrect)
                    .build();
            answerDetailMapper.insert(detail);
        }

        BigDecimal score = pointsPerQuestion.multiply(new BigDecimal(correctCount));

        // 6. 更新考试记录
        record.setScore(score);
        record.setEndTime(LocalDateTime.now());
        record.setStatus(status);
        examRecordMapper.updateById(record);

        log.info("[lbl][Exam][SUBMIT] 提交考试, userId={}, recordId={}, score={}, status={}",
                userId, req.getRecordId(), score, status.getValue());

        // 7. 构建响应
        ExamSubmitResponse response = new ExamSubmitResponse();
        response.setScore(score);
        response.setStatus(status.getValue());
        return response;
    }

    /**
     * 考生端-分页查询考试记录列表
     */
    public IPage<RecordDetailResponse> listRecords(Long userId, int page, int size) {
        Page<ExamRecord> recordPage = examRecordMapper.selectPage(
                new Page<>(page, size),
                new LambdaQueryWrapper<ExamRecord>()
                        .eq(ExamRecord::getUserId, userId)
                        .orderByDesc(ExamRecord::getCreatedAt));

        // 批量获取考试标题
        Set<Long> examIds = recordPage.getRecords().stream()
                .map(ExamRecord::getExamId)
                .collect(Collectors.toSet());
        Map<Long, String> examTitleMap = examIds.isEmpty()
                ? Collections.emptyMap()
                : examMapper.selectBatchIds(examIds).stream()
                        .collect(Collectors.toMap(Exam::getId, Exam::getTitle));

        // 转换
        Page<RecordDetailResponse> resultPage = new Page<>(page, size, recordPage.getTotal());
        resultPage.setRecords(recordPage.getRecords().stream()
                .map(r -> buildRecordSummary(r, examTitleMap.getOrDefault(r.getExamId(), "")))
                .collect(Collectors.toList()));
        return resultPage;
    }

    /**
     * 考生端-查询考试记录详情（含答题明细）
     */
    public RecordDetailResponse getRecordDetail(Long recordId, Long userId) {
        ExamRecord record = examRecordMapper.selectById(recordId);
        if (record == null) {
            throw new BizException(ErrorCode.RECORD_NOT_FOUND);
        }
        if (!record.getUserId().equals(userId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }

        Exam exam = examMapper.selectById(record.getExamId());
        String examTitle = exam != null ? exam.getTitle() : "";

        // 查询答题明细
        List<AnswerDetail> answerDetails = answerDetailMapper.selectList(
                new LambdaQueryWrapper<AnswerDetail>()
                        .eq(AnswerDetail::getRecordId, recordId));

        // 查询对应题目
        List<Long> questionIds = answerDetails.stream()
                .map(AnswerDetail::getQuestionId)
                .collect(Collectors.toList());
        Map<Long, QuestionBank> questionMap = questionIds.isEmpty()
                ? Collections.emptyMap()
                : questionBankMapper.selectBatchIds(questionIds).stream()
                        .collect(Collectors.toMap(QuestionBank::getId, Function.identity()));

        // 构建答题明细 VO
        boolean showAnswer = exam != null && Boolean.TRUE.equals(exam.getShowAnswer());
        boolean showAnalysis = exam != null && Boolean.TRUE.equals(exam.getShowAnalysis());

        List<RecordDetailResponse.AnswerDetailVO> answerVOs = answerDetails.stream()
                .map(ad -> {
                    QuestionBank q = questionMap.get(ad.getQuestionId());
                    RecordDetailResponse.AnswerDetailVO vo = new RecordDetailResponse.AnswerDetailVO();
                    vo.setQuestionId(ad.getQuestionId());
                    vo.setUserAnswer(ad.getUserAnswer());
                    vo.setIsCorrect(ad.getIsCorrect());
                    if (q != null) {
                        vo.setContent(q.getContent());
                        vo.setOptionA(q.getOptionA());
                        vo.setOptionB(q.getOptionB());
                        vo.setOptionC(q.getOptionC());
                        vo.setOptionD(q.getOptionD());
                        vo.setCorrectAnswer(showAnswer ? q.getCorrectAnswer() : null);
                        vo.setAnalysis(showAnalysis ? q.getAnalysis() : null);
                    }
                    return vo;
                })
                .collect(Collectors.toList());

        RecordDetailResponse response = buildRecordSummary(record, examTitle);
        response.setAnswers(answerVOs);
        return response;
    }

    // ==================== 私有方法 ====================

    /**
     * 查询已发布考试，不存在或未发布则抛异常
     */
    private Exam getPublishedExamOrThrow(Long examId) {
        Exam exam = examMapper.selectById(examId);
        if (exam == null || exam.getStatus() != ExamStatus.PUBLISHED) {
            throw new BizException(ErrorCode.EXAM_NOT_PUBLISHED);
        }
        return exam;
    }

    /**
     * 检查用户是否有权访问该考试
     */
    private void checkAccess(Exam exam, Long userId) {
        if (!hasAccess(exam, userId)) {
            throw new BizException(ErrorCode.FORBIDDEN);
        }
    }

    /**
     * 判断用户是否有权访问该考试
     */
    private boolean hasAccess(Exam exam, Long userId) {
        if (exam.getAccessMode() == AccessMode.OPEN) {
            return true;
        }
        // 白名单模式：检查用户是否在白名单中
        long count = examWhitelistMapper.selectCount(
                new LambdaQueryWrapper<ExamWhitelist>()
                        .eq(ExamWhitelist::getExamId, exam.getId())
                        .eq(ExamWhitelist::getUserId, userId));
        return count > 0;
    }

    /**
     * 统计用户在某考试下已完成的记录数（submitted + timeout）
     */
    private long countCompletedRecords(Long examId, Long userId) {
        return examRecordMapper.selectCount(
                new LambdaQueryWrapper<ExamRecord>()
                        .eq(ExamRecord::getExamId, examId)
                        .eq(ExamRecord::getUserId, userId)
                        .in(ExamRecord::getStatus, RecordStatus.SUBMITTED, RecordStatus.TIMEOUT));
    }

    /**
     * 抽题逻辑：随机抽取指定数量的题目
     */
    private List<QuestionBank> drawQuestions(List<QuestionBank> allQuestions, Integer questionCount) {
        List<QuestionBank> pool = new ArrayList<>(allQuestions);
        if (questionCount == null || questionCount == 0 || questionCount >= pool.size()) {
            // 使用全部题目，打乱顺序
            Collections.shuffle(pool);
            return pool;
        }
        // 随机抽取指定数量
        Collections.shuffle(pool);
        List<QuestionBank> selected = new ArrayList<>(pool.subList(0, questionCount));
        // 再次打乱保证随机顺序
        Collections.shuffle(selected);
        return selected;
    }

    /**
     * 构建考试详情响应
     */
    private ExamDetailResponse buildExamDetailResponse(Exam exam, Long userId) {
        ExamDetailResponse resp = new ExamDetailResponse();
        resp.setId(exam.getId());
        resp.setTitle(exam.getTitle());
        resp.setStatus(exam.getStatus().getValue());
        resp.setTimeLimitMin(exam.getTimeLimitMin());
        resp.setMaxAttempts(exam.getMaxAttempts());
        resp.setShowAnswer(exam.getShowAnswer());
        resp.setShowAnalysis(exam.getShowAnalysis());
        resp.setAccessMode(exam.getAccessMode().getValue());

        // 查询题库实际题目数
        long actualCount = questionBankMapper.selectCount(
                new LambdaQueryWrapper<QuestionBank>()
                        .eq(QuestionBank::getExamId, exam.getId()));
        resp.setTotalQuestionCount((int) actualCount);
        // questionCount 为抽题数量，0 表示全部
        int displayCount = (exam.getQuestionCount() == null || exam.getQuestionCount() == 0)
                ? (int) actualCount
                : Math.min(exam.getQuestionCount(), (int) actualCount);
        resp.setQuestionCount(displayCount);

        // 计算剩余次数
        if (exam.getMaxAttempts() == null || exam.getMaxAttempts() == 0) {
            resp.setRemainingAttempts(null);
        } else {
            long completed = countCompletedRecords(exam.getId(), userId);
            resp.setRemainingAttempts(Math.max(0, exam.getMaxAttempts() - (int) completed));
        }

        // 查询是否有进行中的考试记录
        ExamRecord inProgressRecord = examRecordMapper.selectOne(
                new LambdaQueryWrapper<ExamRecord>()
                        .eq(ExamRecord::getExamId, exam.getId())
                        .eq(ExamRecord::getUserId, userId)
                        .eq(ExamRecord::getStatus, RecordStatus.IN_PROGRESS)
                        .last("LIMIT 1"));
        if (inProgressRecord != null) {
            resp.setInProgressRecordId(inProgressRecord.getId());
        }

        return resp;
    }

    /**
     * 构建记录摘要（不含答题明细）
     */
    private RecordDetailResponse buildRecordSummary(ExamRecord record, String examTitle) {
        RecordDetailResponse resp = new RecordDetailResponse();
        resp.setId(record.getId());
        resp.setExamId(record.getExamId());
        resp.setExamTitle(examTitle);
        resp.setScore(record.getScore());
        resp.setStartTime(record.getStartTime());
        resp.setEndTime(record.getEndTime());
        resp.setStatus(record.getStatus().getValue());
        resp.setAttemptNo(record.getAttemptNo());
        return resp;
    }
}

