import { useState, Fragment } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { ArrowLeft, ChevronDown, ChevronRight, Check, X } from "lucide-react"
import { Button } from "@/components/ui/button"
import { formatDateTime } from "@/lib/utils"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useScoreAnalysis, useQuestionAnalysis, useAdminRecordDetail } from "@/hooks/use-admin-analysis"

export const Route = createFileRoute("/_layout/admin/exams/$id/analysis")({
  component: AnalysisPage,
})

function AnalysisPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/analysis" })
  const examId = Number(id)

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <Button variant="ghost" size="icon" onClick={() => navigate({ to: "/admin/exams" })}>
          <ArrowLeft className="h-4 w-4" />
        </Button>
        <h1 className="text-xl font-semibold">{t("admin.analysisTab")}</h1>
      </div>
      <Tabs defaultValue="scores">
        <TabsList>
          <TabsTrigger value="scores">{t("admin.scoreAnalysis")}</TabsTrigger>
          <TabsTrigger value="questions">{t("admin.questionAnalysis")}</TabsTrigger>
        </TabsList>
        <TabsContent value="scores">
          <ScoreTab examId={examId} />
        </TabsContent>
        <TabsContent value="questions">
          <QuestionTab examId={examId} />
        </TabsContent>
      </Tabs>
    </div>
  )
}

/** 展开的答题明细 */
function AnswerDetails({ examId, recordId }: { examId: number; recordId: number }) {
  const { t } = useTranslation()
  const { data, isLoading } = useAdminRecordDetail(examId, recordId)

  if (isLoading) {
    return <div className="py-4 text-center text-sm text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.answers?.length) {
    return <div className="py-4 text-center text-sm text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-3 py-2">
      {data.answers.map((a, idx) => {
        const options = [
          { key: "A", text: a.optionA },
          { key: "B", text: a.optionB },
          { key: "C", text: a.optionC },
          { key: "D", text: a.optionD },
        ]
        return (
          <div key={a.questionId} className="rounded-md border p-3 space-y-2">
            <div className="flex items-start justify-between gap-2">
              <p className="text-sm font-medium">
                {idx + 1}. {a.content}
              </p>
              {a.isCorrect ? (
                <Check className="h-4 w-4 shrink-0 text-green-600" />
              ) : (
                <X className="h-4 w-4 shrink-0 text-red-500" />
              )}
            </div>
            <div className="grid grid-cols-2 gap-x-6 gap-y-1 text-sm">
              {options.map((opt) => {
                const isUserAnswer = a.userAnswer === opt.key
                const isCorrect = a.correctAnswer === opt.key
                let cls = "text-muted-foreground"
                if (isCorrect) cls = "font-semibold text-green-700"
                if (isUserAnswer && !isCorrect) cls = "font-semibold text-red-500 line-through"
                return (
                  <div key={opt.key} className={cls}>
                    {opt.key}. {opt.text}
                    {isCorrect && " ✓"}
                    {isUserAnswer && !isCorrect && ` (${t("exam.yourAnswer")})`}
                  </div>
                )
              })}
            </div>
            {a.analysis && (
              <p className="text-xs text-muted-foreground mt-1">
                {t("admin.analysis")}: {a.analysis}
              </p>
            )}
          </div>
        )
      })}
    </div>
  )
}

/** 得分情况 Tab */
function ScoreTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const [page, setPage] = useState(1)
  const [expandedRecordId, setExpandedRecordId] = useState<number | null>(null)
  const pageSize = 10
  const { data, isLoading } = useScoreAnalysis(examId, page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  if (isLoading) {
