      </Tabs>
    </div>
  )
}

/** 展开的答题明细 */
function AnswerDetails({ examId, recordId }: { examId: number; recordId: number }) {
  const { t } = useTranslation()
  const { data, isLoading } = useAdminRecordDetail(examId, recordId)

  if (isLoading) {
    return <div className="py-4 text-center text-sm text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.answers?.length) {
    return <div className="py-4 text-center text-sm text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-3 py-2">
      {data.answers.map((a, idx) => {
        const options = [
          { key: "A", text: a.optionA },
          { key: "B", text: a.optionB },
          { key: "C", text: a.optionC },
          { key: "D", text: a.optionD },
        ]
        return (
          <div key={a.questionId} className="rounded-md border p-3 space-y-2">
            <div className="flex items-start justify-between gap-2">
              <p className="text-sm font-medium">
                {idx + 1}. {a.content}
              </p>
              {a.isCorrect ? (
                <Check className="h-4 w-4 shrink-0 text-green-600" />
              ) : (
                <X className="h-4 w-4 shrink-0 text-red-500" />
              )}
            </div>
            <div className="grid grid-cols-2 gap-x-6 gap-y-1 text-sm">
              {options.map((opt) => {
                const isUserAnswer = a.userAnswer === opt.key
                const isCorrect = a.correctAnswer === opt.key
                let cls = "text-muted-foreground"
                if (isCorrect) cls = "font-semibold text-green-700"
                if (isUserAnswer && !isCorrect) cls = "font-semibold text-red-500 line-through"
                return (
                  <div key={opt.key} className={cls}>
                    {opt.key}. {opt.text}
                    {isCorrect && " ✓"}
                    {isUserAnswer && !isCorrect && ` (${t("exam.yourAnswer")})`}
                  </div>
                )
              })}
            </div>
            {a.analysis && (
              <p className="text-xs text-muted-foreground mt-1">
                {t("admin.analysis")}: {a.analysis}
              </p>
            )}
          </div>
        )
      })}
    </div>
  )
